const PRICE = {
  input:       1.1   / 1_000_000,
  inputCached: 0.275 / 1_000_000,
  output:      4.4   / 1_000_000,
};

function pickUsage(obj = {}) {
  const v1 = obj.kwargs?.response_metadata?.usage;
  if (v1) {
    return {
      prompt:       v1.prompt_tokens       ?? v1.input_tokens       ?? 0,
      completion:   v1.completion_tokens   ?? v1.output_tokens      ?? 0,
      cached:       v1.prompt_tokens_details?.cached_tokens ?? 0,
    };
  }
  const v2 = obj.usage_metadata;
  if (v2) {
    return {
      prompt:       v2.input_tokens  ?? 0,
      completion:   v2.output_tokens ?? 0,
      cached:       v2.input_token_details?.cache_read ?? 0,
    };
  }
  const v3 = obj.usage;
  if (v3) {
    return {
      prompt:       v3.prompt_tokens ?? v3.input_tokens ?? 0,
      completion:   v3.completion_tokens ?? v3.output_tokens ?? 0,
      cached:       v3.cached_tokens ?? 0,
    };
  }
  return { prompt: 0, completion: 0, cached: 0 };
}

let promptT = 0, completionT = 0, cachedT = 0;
const steps = [];
let summary = '';

for (const item of $input.all()) {
  const conversations = Array.isArray(item.json) ? item.json : [item.json];

  for (const convo of conversations) {
    summary = convo.output ?? summary;

    if (Array.isArray(convo.intermediateSteps)) {
      for (const step of convo.intermediateSteps) {
        if (!step.action) continue;

        const msg = step.action.messageLog?.[0] ?? step.action;
        const u = pickUsage(msg);
        promptT     += u.prompt;
        completionT += u.completion;
        cachedT     += u.cached;

        steps.push({
          tool:        step.action.tool,
          toolInput:   step.action.toolInput,
          observation: step.observation,
        });
      }
    }
  }
}

const nonCached = promptT - cachedT;
const cost = (nonCached * PRICE.input) +
             (cachedT   * PRICE.inputCached) +
             (completionT * PRICE.output);

const result = {
  summary,
  promptTokens:     promptT,
  completionTokens: completionT,
  cachedTokens:     cachedT,
  costUSD:          +cost.toFixed(6),
  totalCostUSD:     +cost.toFixed(6), // opcional: pode remover se quiser evitar repeti√ß√£o
  steps
};

// --- Normaliza√ß√£o pro Supabase (opcional se j√° tiver campos fixos na tabela) ---
const allKeys = [...new Set(Object.keys(result))];
const norm = {};
for (const key of allKeys) {
  norm[key] = result[key] ?? null;
}

return [{ json: norm }];

// Ordena as mensagens pela data
items.sort((a, b) => new Date(a.json.created_at) - new Date(b.json.created_at));

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, '0');
  const mes = String(d.getMonth() + 1).padStart(2, '0');
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of items) {
  const row = item.json;
  const dataFormatada = formatarData(row.created_at);

  if (row.mensagem_usuario && row.mensagem_usuario.trim() !== "") {
    historico.push(`${dataFormatada} - Usu√°rio: ${row.mensagem_usuario.trim()}`);
  }

  if (row.mensagem_agente && row.mensagem_agente.trim() !== "") {
    historico.push(`${dataFormatada} - Agente: ${row.mensagem_agente.trim()}`);
  }
}

return [
  {
    json: {
      historico_conversa: historico.join("\n\n")
    }
  }
];

const items = $input.all();

const processedItems = items.map(item => {
  // O n8n recebe o JSON do webhook dentro de .body
  const data = item.json.body || item.json;

  // Busca o telefone em m√ļltiplas localiza√ß√Ķes poss√≠veis do JSON do Chatwoot
  const phoneNumber = 
    data.sender?.phone_number || 
    data.conversation?.meta?.sender?.phone_number || 
    data.conversation?.contact?.phone_number || 
    "";

  const content = data.content || "";

  // Limpa o n√ļmero: remove o '+' e mant√©m apenas d√≠gitos
  const cleanNumber = phoneNumber.replace(/\D/g, '');

  /**
   * REGRAS DE VALIDA√á√ÉO:
   * 1. Comprimento entre 10 e 15 d√≠gitos
   * 2. Ignora mensagens de sistema (Conectado com sucesso)
   * 3. Ignora n√ļmeros fakes de sistema (123456)
   */
  const isSystemMessage = content.includes("Conectado com sucesso");
  const isFakeNumber = cleanNumber === "123456" || cleanNumber === "";
  const hasValidLength = cleanNumber.length >= 10 && cleanNumber.length <= 15;

  const isValid = hasValidLength && !isSystemMessage && !isFakeNumber;

  return {
    json: {
      ...item.json,
      is_valid_phone: isValid,
      cleaned_phone: cleanNumber,
      debug_phone_found: phoneNumber // Campo para voc√™ conferir se ele achou o n√ļmero
    }
  };
});

return processedItems;

